  "description": "Search courses by syllabus content. This tool specifically searches within course syllabus fields including: - 課程簡述 (Course description) - 課程目標 (Course objectives) - 教學方法 (Teaching methods) - 評量方法 (Assessment methods) - 每週授課內容 (Weekly course content) - 教科書與參考書目 (Textbooks and references) - 核心能力與配比 (Core competencies and weightings) - 課程教材 (Course materials) JSON string containing courses with matching syllabus content",
  "required_parameters": [
    {
      "name": "keyword",
      "type": "STRING",
      "description": "Search keyword to find in syllabus content"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 10)",
      "default": 10
    },
    {
      "name": "include_syllabus_in_result",
      "type": "BOOLEAN",
      "description": "Include full syllabus in results (default: False)",
      "default": false
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

